178→								value={stats.unique_users.toString()}
179→								icon={Users}
180→								subtitle="Contributing feedback"
181→							/>
182→							<StatCard
183→								title="Projects"
184→								value={stats.unique_projects.toString()}
185→								icon={FolderKanban}
186→								subtitle="With learnings captured"
187→							/>
188→						</div>
189→					)}
190→
191→					{/* Filters */}
192→					<div className="mb-6 flex flex-wrap gap-4">
193→						<MultiSelect
194→							options={userDisplayOptions}
195→							selected={selectedUsers.map(
196→								(userId) =>
197→									userMap.get(userId) || `${userId.substring(0, 8)}...`,
198→							)}
199→							onChange={handleUserFilterChange}
200→							placeholder="All Users"
201→							className="w-64"
202→						/>
203→						<MultiSelect
204→							options={projectDisplayOptions}
205→							selected={selectedProjects.map((path) => {
206→								const name = path.split("/").pop() || path;
207→								return name;
208→							})}
209→							onChange={handleProjectFilterChange}
210→							placeholder="All Projects"
211→							className="w-64"
212→						/>
213→						{(selectedUsers.length > 0 || selectedProjects.length > 0) && (
214→							<button
215→								type="button"
216→								onClick={() => {
217→									setSelectedUsers([]);
218→									setSelectedProjects([]);
219→								}}
220→								className="px-4 py-2 text-sm text-muted hover:text-foreground hover:bg-hover rounded-md transition-colors"
221→							>
222→								Clear filters
223→							</button>
224→						)}
225→					</div>
226→
227→					{/* Learnings Trend Chart */}
228→					{trendData && trendData.length > 0 && (
229→						<AnalyticsCard className="mb-6">
230→							<h2 className="text-xl font-bold text-heading mb-4">
231→								Learnings Over Time
232→							</h2>
233→							<p className="text-sm text-muted mb-6">
234→								Feedback activity over time split by developer
235→							</p>
236→							<LearningsTrendChart
237→								data={trendData}
238→								splitBy={splitBy}
239→								onSplitByChange={setSplitBy}
240→								userMap={userMap}
241→							/>
242→						</AnalyticsCard>
243→					)}
244→
245→					{/* Timeline */}
246→					<AnalyticsCard>
247→						<div className="p-6">
248→							{filteredLearnings.length > 0 && (
249→								<div className="flex items-center justify-end mb-6">
250→									<span className="text-sm text-muted">
251→										{filteredLearnings.length}{" "}
252→										{filteredLearnings.length === 1 ? "learning" : "learnings"}
253→									</span>
254→								</div>
255→							)}
256→
257→							<LearningsTimeline
258→								learnings={filteredLearnings}
259→								isLoading={isLoading}
260→								userMap={Object.fromEntries(userMap)}
261→							/>
262→						</div>
263→					</AnalyticsCard>
264→				</>
265→			)}
266→		</div>
267→	);
268→}
