  1→import { z } from "zod";
  2→
  3→// Content block schemas
  4→export const TextContentSchema = z.object({
  5→	type: z.literal("text"),
  6→	text: z.string(),
  7→});
  8→
  9→export const ThinkingContentSchema = z.object({
 10→	type: z.literal("thinking"),
 11→	thinking: z.string(),
 12→	signature: z.string().optional(),
 13→});
 14→
 15→export const ToolUseContentSchema = z.object({
 16→	type: z.literal("tool_use"),
 17→	id: z.string(),
 18→	name: z.string(),
 19→	input: z.record(z.string(), z.unknown()),
 20→});
 21→
 22→export const ToolResultContentSchema = z.object({
 23→	type: z.literal("tool_result"),
 24→	tool_use_id: z.string(),
 25→	content: z.union([
 26→		z.string(),
 27→		z.array(
 28→			z.union([
 29→				TextContentSchema,
 30→				z.object({ type: z.literal("image"), source: z.unknown() }),
 31→			]),
 32→		),
 33→	]),
 34→	is_error: z.boolean().optional(),
 35→});
 36→
 37→// Message schemas
 38→export const UserMessageSchema = z.object({
 39→	role: z.literal("user"),
 40→	content: z.union([
 41→		z.string(),
 42→		z.array(z.union([z.string(), TextContentSchema, ToolResultContentSchema])),
 43→	]),
 44→});
 45→
 46→export const AssistantMessageSchema = z.object({
 47→	role: z.literal("assistant"),
 48→	content: z.array(
 49→		z.union([TextContentSchema, ThinkingContentSchema, ToolUseContentSchema]),
 50→	),
 51→});
 52→
 53→// Entry schemas
 54→const BaseEntrySchema = z.object({
 55→	uuid: z.string(),
 56→	timestamp: z.string(),
 57→	sessionId: z.string(),
 58→});
 59→
 60→export const UserEntrySchema = BaseEntrySchema.extend({
 61→	type: z.literal("user"),
 62→	message: UserMessageSchema,
 63→});
 64→
 65→export const AssistantEntrySchema = BaseEntrySchema.extend({
 66→	type: z.literal("assistant"),
 67→	message: AssistantMessageSchema,
 68→});
 69→
 70→export const SummaryEntrySchema = z.object({
 71→	type: z.literal("summary"),
 72→	summary: z.string(),
 73→});
 74→
 75→export const SystemEntrySchema = BaseEntrySchema.extend({
 76→	type: z.literal("system"),
 77→	message: z.object({ content: z.string() }),
 78→});
 79→
 80→// Union type
 81→export const ConversationSchema = z.union([
 82→	UserEntrySchema,
 83→	AssistantEntrySchema,
 84→	SummaryEntrySchema,
 85→	SystemEntrySchema,
 86→]);
 87→
 88→export type TextContent = z.infer<typeof TextContentSchema>;
 89→export type ThinkingContent = z.infer<typeof ThinkingContentSchema>;
 90→export type ToolUseContent = z.infer<typeof ToolUseContentSchema>;
 91→export type ToolResultContent = z.infer<typeof ToolResultContentSchema>;
 92→export type UserEntry = z.infer<typeof UserEntrySchema>;
 93→export type AssistantEntry = z.infer<typeof AssistantEntrySchema>;
 94→export type SummaryEntry = z.infer<typeof SummaryEntrySchema>;
 95→export type SystemEntry = z.infer<typeof SystemEntrySchema>;
 96→export type Conversation = z.infer<typeof ConversationSchema>;
 97→
 98→// Parser
 99→export function parseConversations(content: string): Array<Conversation> {
100→	const conversations: Array<Conversation> = [];
101→	const lines = content.split("\n").filter(Boolean);
102→
103→	for (const line of lines) {
104→		try {
105→			const parsed = JSON.parse(line) as unknown;
106→			const result = ConversationSchema.safeParse(parsed);
107→			if (result.success) {
108→				conversations.push(result.data);
109→			}
110→		} catch {
111→			// Skip malformed lines
112→		}
113→	}
114→
115→	return conversations;
116→}
