  1→import type {
  2→	Conversation,
  3→	SummaryEntry,
  4→	ToolResultContent,
  5→	UserEntry,
  6→} from "@/lib/conversation-schema";
  7→import type { ParsedSlashCommand } from "@/lib/parse-slash-command";
  8→import {
  9→	isSlashCommandMessage,
 10→	parseSlashCommand,
 11→} from "@/lib/parse-slash-command";
 12→import { ConversationItem } from "./ConversationItem";
 13→import { SlashCommandContent } from "./SlashCommandContent";
 14→import { SummaryGroup } from "./SummaryGroup";
 15→
 16→interface ConversationListProps {
 17→	conversations: Array<Conversation>;
 18→	getToolResult: (toolUseId: string) => ToolResultContent | undefined;
 19→	subagents: Map<string, Array<Conversation>>;
 20→}
 21→
 22→export function ConversationList({
 23→	conversations,
 24→	getToolResult,
 25→	subagents,
 26→}: ConversationListProps) {
 27→	if (conversations.length === 0) {
 28→		return (
 29→			<div className="flex items-center justify-center h-64 text-muted-foreground">
 30→				No conversation data
 31→			</div>
 32→		);
 33→	}
 34→
 35→	// Group consecutive summaries and slash commands together
 36→	const groupedConversations = groupConversations(conversations);
 37→
 38→	return (
 39→		<ul className="space-y-2">
 40→			{groupedConversations.map((item, index) => {
 41→				const prevItem =
 42→					index > 0 ? groupedConversations[index - 1] : undefined;
 43→				const prevType = getPrevType(prevItem);
 44→
 45→				if ("summaries" in item) {
 46→					return (
 47→						<li key={`summary-group-${item.summaries[0].summary.slice(0, 32)}`}>
 48→							<SummaryGroup summaries={item.summaries} />
 49→						</li>
 50→					);
 51→				}
 52→
 53→				if ("slashCommand" in item) {
 54→					return (
 55→						<li key={item.userEntry.uuid}>
 56→							<SlashCommandContent
 57→								command={item.slashCommand}
 58→								followingExpandedContent={item.followingExpandedContent}
 59→								showIcon={prevType !== "user"}
 60→							/>
 61→						</li>
 62→					);
 63→				}
 64→
 65→				return (
 66→					<li key={"uuid" in item ? item.uuid : `item-${index}`}>
 67→						<ConversationItem
 68→							conversation={item}
 69→							getToolResult={getToolResult}
 70→							subagents={subagents}
 71→							showIcon={item.type !== prevType}
 72→						/>
 73→					</li>
 74→				);
 75→			})}
 76→		</ul>
 77→	);
 78→}
 79→
 80→function getPrevType(
 81→	prevItem: GroupedItem | undefined,
 82→): "summary" | "user" | "assistant" | "system" | null {
 83→	if (!prevItem) return null;
 84→	if ("summaries" in prevItem) return "summary";
 85→	if ("slashCommand" in prevItem) return "user";
 86→	return prevItem.type;
 87→}
 88→
 89→/** A slash command group: user entry with parsed command + optional expanded content */
 90→interface SlashCommandGroup {
 91→	slashCommand: ParsedSlashCommand;
 92→	userEntry: UserEntry;
 93→	/** Expanded content from a following message (system or user, if not in same user message) */
 94→	followingExpandedContent?: string;
 95→}
 96→
 97→/** Extract text content from user message content (string or array) */
 98→function extractUserTextContent(
 99→	content: string | Array<string | { type: string; text?: string }>,
100→): string {
101→	if (typeof content === "string") {
102→		return content;
103→	}
104→	return content
105→		.filter(
106→			(block): block is string | { type: "text"; text: string } =>
107→				typeof block === "string" ||
108→				(typeof block === "object" && block.type === "text"),
109→		)
110→		.map((block) => (typeof block === "string" ? block : block.text))
111→		.join("\n");
112→}
113→
114→type GroupedItem =
115→	| Conversation
116→	| { summaries: Array<SummaryEntry> }
117→	| SlashCommandGroup;
118→
119→/**
120→ * Group conversations for display:
121→ * - Consecutive summaries are grouped together
122→ * - Slash command user messages are grouped with their following system message
123→ */
124→function groupConversations(
125→	conversations: Array<Conversation>,
126→): Array<GroupedItem> {
127→	const result: Array<GroupedItem> = [];
128→	let currentSummaryGroup: Array<SummaryEntry> = [];
129→	let i = 0;
130→
131→	while (i < conversations.length) {
132→		const conv = conversations[i];
133→
134→		// Handle summaries - group consecutive ones
135→		if (conv.type === "summary") {
136→			currentSummaryGroup.push(conv);
137→			i++;
138→			continue;
139→		}
140→
141→		// Flush summary group if we have one
142→		if (currentSummaryGroup.length > 0) {
143→			result.push({ summaries: currentSummaryGroup });
144→			currentSummaryGroup = [];
145→		}
146→
147→		// Check for slash command pattern in user message
148→		if (conv.type === "user") {
149→			const content = conv.message.content;
150→
151→			if (isSlashCommandMessage(content)) {
152→				const parsed = parseSlashCommand(content);
153→				if (parsed) {
154→					const slashCommandGroup: SlashCommandGroup = {
155→						slashCommand: parsed,
156→						userEntry: conv,
157→					};
158→
159→					// If there's no expanded content in the user message itself,
160→					// check if the next message contains the expanded content
161→					if (!parsed.expandedContent) {
162→						const nextConv = conversations[i + 1] as Conversation | undefined;
163→						// Expanded content can be in a following system message
164→						if (nextConv?.type === "system") {
165→							slashCommandGroup.followingExpandedContent =
166→								nextConv.message.content;
167→							i++; // Skip in main loop
168→						}
169→						// Or in a following user message (without command tags)
170→						else if (
171→							nextConv?.type === "user" &&
172→							!isSlashCommandMessage(nextConv.message.content)
173→						) {
174→							slashCommandGroup.followingExpandedContent =
175→								extractUserTextContent(nextConv.message.content);
176→							i++; // Skip in main loop
177→						}
178→					}
179→
180→					result.push(slashCommandGroup);
181→					i++;
182→					continue;
183→				}
184→			}
185→		}
186→
187→		// Regular conversation item
188→		result.push(conv);
189→		i++;
190→	}
191→
192→	// Don't forget any trailing summaries
193→	if (currentSummaryGroup.length > 0) {
194→		result.push({ summaries: currentSummaryGroup });
195→	}
196→
197→	return result;
198→}
